code.imports:
import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { Button, icon } from 'decantr/components';

code.example:
function Hero() {
  const { div, h1, p } = tags;

  return div({ class: css('_flex _col _aic _tc _gap6 _py16 _px6') },
    h1({ class: css('_heading1') }, 'Build Faster, Ship Smarter'),
    p({ class: css('_body _fgmuted _mw[640px]') }, 'The AI-first framework that turns your ideas into production-ready applications in minutes, not months.'),
    div({ class: css('_flex _gap3') },
      Button({ variant: 'primary', size: 'lg' }, 'Get Started'),
      Button({ variant: 'outline', size: 'lg' }, icon('github'), 'View Source')
    )
  );
}

code.imports:
import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { Button, Chip, icon } from 'decantr/components';
import { navigate } from 'decantr/router';

code.example:
function ImageOverlayHero({ item }) {
  const { div, h1, p, img } = tags;

  return div({ class: css('_relative _wfull _h[400px] _overflow[hidden] _r4') },
    img({ src: item.image, alt: item.title, class: css('_absolute _inset0 _wfull _hfull _object[cover]') }),
    div({ class: css('_absolute _inset0 _bg[linear-gradient(transparent_50%,rgba(0,0,0,0.8))]') }),
    div({ class: css('_absolute _top0 _left0 _right0 _flex _jcsb _p4') },
      Button({ variant: 'ghost', size: 'sm', onclick: () => navigate(-1) }, icon('arrow-left'), 'Back'),
      Button({ variant: 'ghost', size: 'sm' }, icon('edit'), 'Edit')
    ),
    div({ class: css('_absolute _bottom0 _left0 _right0 _p6 _flex _col _gap2') },
      div({ class: css('_flex _gap2') },
        ...(item.tags || []).map(t => Chip({ size: 'sm', variant: 'outline' }, t))
      ),
      h1({ class: css('_heading2 _fgfg') }, item.title),
      p({ class: css('_body _fgmuted') }, item.description)
    )
  );
}

