import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { Button, Badge, Avatar, icon } from 'decantr/components';

code.example:
function CompactOverlayHero({ item }) {
  const { div, h1, span, img } = tags;

  return div({ class: css('_relative _wfull _h[300px] _overflow[hidden] _r4') },
    img({ src: item.cover, alt: item.title, class: css('_absolute _inset0 _wfull _hfull _object[cover]') }),
    div({ class: css('_absolute _inset0 _bg[linear-gradient(transparent_50%,rgba(0,0,0,0.8))]') }),
    div({ class: css('_absolute _top0 _right0 _p4 _flex _gap2') },
      Button({ variant: 'ghost', size: 'sm' }, icon('edit'), 'Edit'),
      Button({ variant: 'ghost', size: 'sm' }, icon('trash'), 'Delete')
    ),
    div({ class: css('_absolute _bottom0 _left0 _right0 _p6 _flex _col _gap2') },
      h1({ class: css('_heading2 _fgfg') }, item.title),
      div({ class: css('_flex _aic _gap3') },
        Badge({ variant: 'outline' }, `${item.count} items`),
        div({ class: css('_flex _aic _gap2') },
          Avatar({ src: item.author?.avatar, size: 'xs' }),
          span({ class: css('_textsm') }, item.author?.name)
        )
      )
    )
  );
}

