code.example:
function EmptyState({ icon: ic, title, description, actionLabel, onAction }) {
  const { div, h3, p } = tags;

  return div({ class: css('_flex _col _aic _tc _gap4 _py12 _px6') },
    div({ class: css('_w16 _h16 _flex _center _rfull _bgmuted/10') },
      icon(ic, { size: '2rem', class: css('_fgmuted') })
    ),
    h3({ class: css('_heading4') }, title),
    p({ class: css('_body _fgmuted _mw[480px]') }, description),
    actionLabel ? Button({ variant: 'primary', onclick: onAction }, icon('plus', { size: '1em' }), ` ${actionLabel}`) : null
  );
}

